#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct MessageHeader {
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;
};

MessageHeader read_header_and_skip_body(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor object from the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Declare variables to store the read values
    uint16_t message_type;
    uint32_t body_length;
    uint32_t footer;

    // Use the buffer_adaptor's read function to read the message_type
    adaptor.read(&message_type, sizeof(message_type));

    // Use the buffer_adaptor's read function to read the body_length
    adaptor.read(&body_length, sizeof(body_length));

    // Calculate the body size using body_length and skip that many bytes
    adaptor.skip(body_length);

    // Use the buffer_adaptor's read function to read the footer
