    uint8_t data_type = adaptor[0];

    // Check if buffer has enough data for header (1 byte for data_type + 4 bytes for item_count)
    if (buffer.size() < 5) {
        return DataResult{0, {}, {}};
    }

    // Read the item_count from the buffer (at offset 1, 4 bytes)
    uint32_t item_count;
    adaptor.read(&item_count, sizeof(item_count));

    // Based on data_type, read either uint32_t or float items
    if (data_type == 0) {
        // Read uint32_t items
        std::vector<uint32_t> int_items(item_count);
        adaptor.read(int_items.data(), item_count * sizeof(uint32_t));
        return DataResult{data_type, std::move(int_items), {}};
