Based on the reference materials and detailed specifications, here's the complete implementation for the exam question:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <span>

struct ProtocolPacket {
    uint32_t message_id;
    std::vector<uint16_t> data_values;
    uint32_t checksum;
};

std::vector<uint8_t> serialize_protocol_packet(const ProtocolPacket& packet) {
    // Create a buffer and binary_stream for writing
    std::vector<uint8_t> buffer;
    hexi::binary_stream stream(buffer);

    // Convert message_id to big-endian and write
    uint32_t big_endian_message_id = hexi::endian::native_to_big(packet.message_id);
    stream.write(&big_endian_message_id, sizeof(big_endian_message_id));

    // Convert each data_value to big-endian and write the vector
    std::vector<uint16_t> big_endian_data_values;
    for (auto value : packet.data_values) {
        uint16_t converted = hexi::endian::native_to_big(value);
        big_endian_data_values.push_back(converted);
    }
    stream.write_container(big_endian_data_values);

    // Convert checksum to big-endian and write
    uint32_t big_endian_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(&big_endian_checksum, sizeof(big_endian_checksum));

    return buffer;
}

ProtocolPacket deserialize_protocol_packet(const std::span<const uint8_t> buffer) {
    // Create a buffer from the span and binary_stream for reading
    std::vector<uint8_t> read_buffer(buffer.begin(), buffer.end());
    hexi::binary_stream stream(read_buffer);

    ProtocolPacket packet;

    // Read message_id and convert from big-endian to native
    uint32_t read_message_id;
    stream.read(&read_message_id, sizeof(read_message_id));
    packet.message_id = hexi::endian::big_to_native(read_message_id);

    // Read data_values count and convert from big-endian to native
    uint32_t data_count;
    stream.read(&data_count, sizeof(data_count));
    data_count = hexi::endian::big_to_native(data_count);

    // Read data_values vector and convert each element
    std::vector<uint16_t> data_values;
    stream.read_container(data_values, data_count);
    for (auto& value : data_values) {
        value = hexi::endian::big_to_native(value);
    }
    packet.data_values = std::move(data_values);

    // Read checksum and convert from big-endian to native
    uint32_t read_checksum;
    stream.read(&read_checksum, sizeof(read_checksum));
    packet.checksum = hexi::endian::big_to_native(read_checksum);

    return packet;
}

struct ProtocolHeader {
    uint32_t message_id;
};

ProtocolHeader extract_protocol_header(const std::span<const uint8_t> buffer) {
    // Create a buffer from the span and binary_stream
    std::vector<uint8_t> read_buffer(buffer.begin(), buffer.end());
    hexi::binary_stream stream(read_buffer);

    ProtocolHeader header;

    // Use span() to get message_id and convert with big_to_native
    auto message_span = stream.span(1); // Get 1 uint32_t
    header.message_id = hexi::endian::big_to_native(*message_span);

    // Use skip() to advance past the header
    stream.skip(4); // Skip the 4 bytes of the message_id

    return header;
}
