    std::vector<uint8_t> read_buffer(buffer.begin(), buffer.end());
    hexi::binary_stream stream(read_buffer);

    ProtocolPacket packet;

    // Read message_id and convert from big-endian to native
    uint32_t read_message_id;
    stream.read(&read_message_id, sizeof(read_message_id));
    packet.message_id = hexi::endian::big_to_native(read_message_id);

    // Read data_values count and convert from big-endian to native
    uint32_t data_count;
    stream.read(&data_count, sizeof(data_count));
    data_count = hexi::endian::big_to_native(data_count);

    // Read data_values vector and convert each element
    std::vector<uint16_t> data_values;
    stream.read_container(data_values, data_count);
    for (auto& value : data_values) {
        value = hexi::endian::big_to_native(value);
    }
    packet.data_values = std::move(data_values);

    // Read checksum and convert from big-endian to native
    uint32_t read_checksum;
    stream.read(&read_checksum, sizeof(read_checksum));
    packet.checksum = hexi::endian::big_to_native(read_checksum);

